const mensagens = $json.mensagens;

// filtra apenas mensagens do Lead
const mensagensLead = mensagens.filter(m => m.startsWith('Lead-'));

// pega a última mensagem do Lead
const ultimaMensagem = mensagensLead[mensagensLead.length - 1];

// extrai horário (último bloco após "-")
const partes = ultimaMensagem.split('-');
const horario = partes[partes.length - 1];

const [hora, minuto] = horario.split(':').map(Number);

// hora atual Brasil
const agora = new Date();

const horaAtual = Number(
  agora.toLocaleString('en-US', {
    timeZone: 'America/Sao_Paulo',
    hour: '2-digit',
    hour12: false
  })
);

const minutoAtual = Number(
  agora.toLocaleString('en-US', {
    timeZone: 'America/Sao_Paulo',
    minute: '2-digit'
  })
);

// conversão em minutos
const minutosMensagem = hora * 60 + minuto;
const minutosAtual = horaAtual * 60 + minutoAtual;

// diferença
const diferenca = minutosAtual - minutosMensagem;

return [
  {
    json: {
      ultimaMensagem,
      horarioMensagem: horario,
      diferencaMinutos: diferenca,
      passou3Min: diferenca >= 3
    }
  }
];

